// // This module implements a 5-bit ring counter with asynchronous reset and synchronous enable. The counter shifts '1' to the right on each clock pulse when enabled.
module ring_counter(
    input wire clk,
    input wire reset,
    input wire enable,
    output reg [4:0] count
);
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            count <= 5'b00001;
        end else if (enable) begin
            count <= {count[3:0], count[4]};
        end
    end
endmodule
